var e=JSON.parse(`[{"id":"L10_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"생각보다 저항이 거세군. 침식체가 얼마 남지 않았을 텐데.","JPN":"思ったより抵抗が続くな。残っている侵食体はさほど多くないはずなんだが。","ENG":"The number of C.O.s should be dwindling, but the resistance is stronger than anticipated.","TWN":"沒想到他們比想像中還要頑強抵抗，侵蝕體應該剩不多才對。"},"stage":{"bg":"UNDER","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L13_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"신부님, 제가 길을 알아요. 여기서 조금만 더 가면…….","JPN":"神父様、私、道を知っておりますわ。ここからもうちょっと行くと……","ENG":"Father, I know the way. If we go a little further from here...","TWN":"神父，我知道路，再往裡面走……"},"stage":{"bg":"UNDER","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L14_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"UNDER","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L15_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"아니, 클로디아 자네는 신디와 함께 이곳에 남도록.","JPN":"いや。クラウディア、君はシンディと一緒にここに残ってくれたまえ。","ENG":"No, Claudia. You should remain here with Cindy.","TWN":"不，克勞迪婭，你和辛蒂一起留在這裡。"},"stage":{"bg":"UNDER","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L16_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"네? 그렇지만…….","JPN":"はい？　でも……","ENG":"What? B-but...","TWN":"什麼？可是……"},"stage":{"bg":"UNDER","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"저것들이 이렇게까지 거세게 저항하는 건, 필히 저 심연 속에 무언가가 일어나고 있다는 뜻이다.","JPN":"侵食体がここまで激しく抵抗するのは、きっとあの深淵の中で何かが起きているという証拠だろう。","ENG":"The only reason those things are resisting so fiercely is because something is happening in the abyss over there.","TWN":"他們會如此頑強抵抗，就表示那個深淵裡一定有什麼。"},"stage":{"bg":"UNDER","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"어쩌면 인신공양을 통한 사악한 의식 같은 것일지도 모르겠지.","JPN":"もしかすると人身御供による邪悪な儀式のようなものかもしれない。","ENG":"Perhaps it is another evil ritual involving human sacrifice.","TWN":"或許是想藉由活祭舉行什麼邪惡的儀式。"},"stage":{"bg":"UNDER","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"그렇다면 자네 말대로 그 아이가 위험할 거다.","JPN":"だとすると、君の言うとおりその子が危ない。","ENG":"If that is true, then that child will be in danger.","TWN":"若真是如此，那你說的那個孩子就會有危險。"},"stage":{"bg":"UNDER","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"네, 그러니까 더욱 저의 도움이…….","JPN":"はい、ですから私の助けが……","ENG":"Yes, then all the more reason for me to─","TWN":"沒錯，所以更需要我的幫……"},"stage":{"bg":"UNDER","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"착각하지 마라, 클로디아.","JPN":"勘違いするな、クラウディア。","ENG":"Do not be mistaken, Claudia.","TWN":"克勞迪婭，你是不是哪裡有誤會？"},"stage":{"bg":"UNDER","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L25_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"이 상황에서 그런 몸으로 자네가 우릴 어떻게 돕겠다는 건가?","JPN":"この状況で、身体も万全でない君がどうやって助けになるというんだ。","ENG":"How are you supposed to help anyone in that condition?","TWN":"以你現在的身體，在這種情況下要如何幫我們？"},"stage":{"bg":"UNDER","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"신부님께서는…… 벌써 눈치채고 계셨군요.","JPN":"神父様は……すでに気付いていらしゃったのですね。","ENG":"Father... I see you've already noticed...","TWN":"神父……原來你有發現。"},"stage":{"bg":"UNDER","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"미안하군. 하지만 이 세상엔 신앙만으로는 해결할 수 없는 문제도 있다.","JPN":"すまない。だが、この世界には信仰だけで解決できない問題もある。","ENG":"My apologies. However, there are some matters in this world that faith alone cannot solve.","TWN":"抱歉，但在這個世界上，有些問題是光靠信仰無法解決的。"},"stage":{"bg":"UNDER","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"그런 문제들을 해결하기 위해서는…… 다른 방식이 필요하지.","JPN":"そのような問題を解決するためには……違う方法が必要なのだ。","ENG":"In order to resolve such issues, we will need... unconventional methods.","TWN":"要解決那些問題……就必須換個方法。"},"stage":{"bg":"UNDER","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"신디! 여긴 네게 맡기겠다. 내가 돌아올 때까지 침식체의 발을 묶어 두도록.","JPN":"シンディ！　ここは君に任せる。私が帰って来るまで侵食体を足止めしておきたまえ。","ENG":"Cindy! I place you in charge here. Keep the C.O.s at bay until I return.","TWN":"辛蒂！這裡交給你，在我回來之前，別讓侵蝕體靠近！"},"stage":{"bg":"UNDER","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L41_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"이미 초과 근무 중이야, 꺽다리.","JPN":"すでに超過勤務中なんだよ、のっぽ。","ENG":"I'm already working overtime, Long Legs!","TWN":"這根本是在加班吧，高個子。"},"stage":{"bg":"UNDER","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"}}},"sfx":"FX_COMBAT_ALL_MECHANIC_WORK_16"},{"id":"L42_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"볼 일 있으면 폼 잡을 시간에 빨랑 갔다 오기나 해.","JPN":"用があるならカッコつけてないで早く行ってきてよ。","ENG":"If you got something to do, stop wasting time and go already!","TWN":"有事要忙就快去啦，少在這廢話。"},"stage":{"bg":"UNDER","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L44_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"후후…… 믿음직스럽군.","JPN":"ふふ……頼もしいな。","ENG":"Hah hah... How trustworthy.","TWN":"呵呵……誰叫你那麼可靠。"},"stage":{"bg":"UNDER","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":null}}},{"id":"L45_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"그럼 뒤를 부탁하겠다. 신디, 클로디아.","JPN":"それでは後を頼んだぞ。シンディ、クラウディア。","ENG":"Then I leave it to you, Cindy, Claudia.","TWN":"那後面就麻煩你們了，辛蒂、克勞迪婭。"},"stage":{"bg":"UNDER","bgm":"BATTLE_COUNTERISDE_NORMAL_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"베네딕트가 아이를 혼자 구조하러 갔다면…….","JPN":"ベネディクトが一人で子どもを救出しに行ったなら……","ENG":"If Benedict went by himself to save the child...","TWN":"你說本尼迪克特自己去救人……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"학회가 벌인 의식을 목격했을 가능성이 매우 큽니다.","JPN":"学会が行っていた儀式を目撃した可能性が非常に高くなりますね。","ENG":"There is a high possibility that he witnessed the ritual of the Society.","TWN":"那他應該有很高的機率看到學會在舉行儀式。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"학회라고요?","JPN":"学会？","ENG":"The Society?","TWN":"學會？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L3_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그 부분은 나중에 따로 설명해드리죠.","JPN":"その辺は後で説明しましょう。","ENG":"Allow me to explain later.","TWN":"這部份我之後再跟你解釋。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L4_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"어쨌든 베네딕트가 아이를 구조한 직후 무언가 이상한 점은 없었습니까?","JPN":"とにかく、ベネディクトが子どもを救助した直後、何かおかしなところはありませんでしたか？","ENG":"Nevertheless, was there anything odd right after Benedict rescued the girl?","TWN":"總之，本尼迪克特救出那個孩子後，有沒有什麼可疑的地方？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L5_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"으음, 신부님은 평소에도 과묵하셔서 딱히 내색은 안 하셨지만…….","JPN":"うーん、神父様は普段から無口な方ですので、特に変った様子は見られませんでしたが……","ENG":"Hmm... Father usually keeps to himself, so he tends to not express his emotions...","TWN":"嗯…神父平時就沉默寡言，喜怒不形於色，不過……"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L6_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"아이를 데리고 돌아온 신부님의 몸에 할퀸 듯한 상처들이 있었어요.","JPN":"子どもを連れて帰ってこられた神父様の身体には引っ掻いたような傷がありましたわ。","ENG":"But when he came back with the girl, he had scratch marks on his body.","TWN":"他將孩子救出來後，身上好像有被抓傷的痕跡。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L8_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"할퀸 상처?","JPN":"引っ掻いたような傷？","ENG":"Scratch marks?","TWN":"抓傷的痕跡？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"확실히 베네딕트의 진료 기록에서 창상과 괴사에 대한 부분이 있었던 것 같군요.","JPN":"確かにベネディクトの診察記録に創傷と壊疽に関する記述があったように思います。","ENG":"Yes, I believe I saw something in his medical records about wounds and necrosis.","TWN":"在本尼迪克特的診斷書上，確實有寫到創傷和壞死的部分。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"네. 침식체에게 당한 상처와는 명확히 달라서 기억해요.","JPN":"はい。侵食体にやられた傷とは明らかに違っていたので覚えています。","ENG":"Yes. I remember it because the wound was clearly different from a C.O. gash.","TWN":"是，因為很明顯和侵蝕體所造成的傷口不同，所以我印象很深刻。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"제 능력만 쓸 수 있었더라도…… 금방 낫게 해드릴 수 있었는데.","JPN":"能力さえ使えたら……すぐに治療してさしあげたのに。","ENG":"If only I could use my ability... I could've healed it.","TWN":"要是我能夠使用能力的話……應該很快就可以幫他治好。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L14_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"루체 자매님, 구조된 어린 양은 어떻게 됐나요?","JPN":"シスター・ルーチェ、救助された子羊はどうなりましたか？","ENG":"Sister Luce, what happened to the rescued young lamb?","TWN":"露契姊妹，那隻得救的小羊現在情況怎麼樣？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L15_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"현재 의식을 회복했습니다만, 정신은 여전히 불안정한 상태입니다.","JPN":"現在意識は取り戻しましたが、相変わらず精神が不安定な状態です。","ENG":"She is currently conscious, but mentally unstable.","TWN":"她目前已經恢復意識，但精神狀況不太穩定。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L17_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"그래도 살아 있어서 다행이네요.","JPN":"それでも助かったのですから幸いですわ。","ENG":"I'm glad that she's alive.","TWN":"只要還活著就好。"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"신부님은 아무 말씀 안 하셨지만…….","JPN":"神父様は何もお話しくださいませんでしたが……","ENG":"I know Father didn't say anything, but...","TWN":"雖然神父沒有提到……"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"그 아이가 살았다는 건 결국 의식이 실패로 돌아갔다는 거겠죠?","JPN":"あの子が助かったということは、結局儀式が失敗したということでしょうね。","ENG":"Since the girl's alive, that means the ritual failed, right?","TWN":"但那孩子活著回來，就表示儀式是失敗的吧？"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"THEMA_DIVE_BOTTOM","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"DAUGHTER_EXTRA_NULL_GIRL","text":{"KOREA":"내놔……! 내놓으라고……!","JPN":"出せ……！　出せよ……！","ENG":"Give it...! Give it back...!","TWN":"放手……！我叫你放手……！"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L24_1","type":"dialog","speaker":"DAUGHTER_EXTRA_NULL_GIRL","text":{"KOREA":"내놔아아아아아……!","JPN":"出せえええええ……！","ENG":"GIVE IT BAAAACK...!","TWN":"那是我的……！！！"},"stage":{"bg":"LAB_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_SEPIA","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"설마…….","JPN":"まさか……","ENG":"What if…","TWN":"難道……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"루체 자매님. 왜 그러세요? 갑자기 안색이 안 좋아지셨어요.","JPN":"シスター・ルーチェ、どうしたのですか？　急に顔色を悪くされて。","ENG":"Sister Luce, what's wrong? You suddenly look ill.","TWN":"露契姊妹，怎麼了？你的臉色不太好。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L30_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"아니요. 아무것도…… 아닙니다.","JPN":"いいえ。何でも……ありません。","ENG":"Nothing. I am... fine.","TWN":"沒事，沒……什麼。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L32_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"사실, 저 콘스탄틴 신부님이 수배 중이라는 편지를 받고 깜짝 놀랐어요.","JPN":"実は、コンスタンティン神父が手配中だという手紙をもらってとても驚いたんです。","ENG":"To be frank, I was surprised to receive a letter saying that Father Constantine is a wanted man.","TWN":"不瞞你說，我收到康斯坦丁神父被通緝的信時很驚訝呢。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"비록 신부님이 말수가 적고 자기 생각을 털어놓지 않으시는 분이긴 해도. 그런 일을 저질렀으리라고는…….","JPN":"神父様は無口でご自身のお考えをあまり口にしない方ではありますけど、そんなことをしたとは……","ENG":"He may not talk much about himself to anyone, but I never imagined him doing something like this...","TWN":"雖然神父平時話不多，也不太吐露自己內心的想法，但應該不至於做出這種事……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"무언가 착오가 있었던 것 아닐까요, 루체 자매님?","JPN":"何か誤解があったのではないですか？　シスター・ルーチェ。","ENG":"Maybe there has been a misunderstanding, Sister Luce?","TWN":"露契姊妹，會不會是哪裡有誤會呢？"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L36_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"기꺼이 정정해 드리죠.","JPN":"喜んで訂正いたします。","ENG":"I would be more than happy to rephrase.","TWN":"我要更正一下。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE"},{"id":"L37_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"<color=#ffd34c>베네딕트가 요한 추기경을 살해했다.</color> 이건 틀림없는 사실입니다.","JPN":"<color=#ffd34c>ベネディクトがヨハン枢機卿を殺した。</color>これは紛れもない事実です。","ENG":"It is a fact that <color=#ffd34c>Benedict murdered Cardinal Johan</color>.","TWN":"<color=#ffd34c>本尼迪克特殺害約翰樞機主教，</color>這是既定的事實。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"왜냐하면…… 제가 그 사건의 목격자니까요.","JPN":"なぜなら……私がその事件の目撃者ですから。","ENG":"I know this because... I am the one who witnessed it.","TWN":"因為……我就是這件事的目擊證人。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"죄송해요……. 제가 자매님의 사정을 좀 더 헤아렸어야 했는데.","JPN":"すみません……私がもっとシスターの事情を考えるべきでした。","ENG":"I'm sorry... I should've been more considerate of your situation.","TWN":"對不起……我應該多站在你的立場想的。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L42_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"아니요. 당신이 사과할 일은 아닐 겁니다. 시스터.","JPN":"いいえ。あなたが謝ることではありません。シスター。","ENG":"No, you do not need to apologize to me, Sister.","TWN":"沒事，你無須道歉。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L43_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그저 제 자신의 한심함과 무력함을 탓할 뿐이죠.","JPN":"ただ私自身の情けさなと無力を責めるだけです。","ENG":"All I can do is blame myself for my helplessness and self-pity.","TWN":"我只怪我自己無能為力。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L44_1","type":"dialog","speaker":"CLOUDIA_VATICAN_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_HATE"},"C":null,"R":{"char_id":"CLOUDIA_VATICAN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"그럼, 당신에 대한 열람은 여기서 마치도록 하죠. ","JPN":"それでは、あなたの閲覧はこのくらいで終わりにしましょう。 ","ENG":"Then, I shall finish browsing you here.","TWN":"那關於你的部分，我就讀到這裡。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"갑자기 떠오른 게 있어 급히 가봐야 겠습니다.","JPN":"急に思いついたことがありますので、急いで帰ります。","ENG":"Something just came up, so I should take my leave.","TWN":"我突然想起有點急事，必須先離開。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"협조해 주셔서 감사합니다. 시스터 넬슨.","JPN":"ご協力、ありがとうございました。シスターネルソン。","ENG":"Thank you for your cooperation, Sister Nelson.","TWN":"謝謝你的配合，尼爾森姊妹。"},"stage":{"bg":"HOSPITAL","bgm":"CUTSCENE_CONSPIRACY","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};